const body = $input.first().json.body || $input.first().json;
const tenantId = body.tenantId;
const limit = Number(body.limit) || 10;
const query = body.query || '';
const label = body.label || 'INBOX';

if (!tenantId) {
  return [{ json: { success: false, error: 'tenantId requis' } }];
}

return [{ json: { tenantId, limit, query, label, valid: true } }];

const emails = $input.all().map(item => {
  const e = item.json;
  if (!e.id) return null;
  return {
    id: e.id || null,
    threadId: e.threadId || null,
    from: e.from || '',
    to: e.to || '',
    subject: e.subject || '(sans objet)',
    date: e.date || null,
    snippet: e.snippet || '',
    textPlain: (e.textPlain || '').substring(0, 500),
    labels: e.labelIds || [],
    hasAttachments: (e.attachments || []).length > 0
  };
}).filter(Boolean);

return [{ json: {
  success: true,
  data: {
    emails,
    count: emails.length
  }
} }];
